const startedAt = new Date().toISOString();
const executionId = $execution.id;
const { v4: uuidv4 } = require('uuid');
const correlationId = uuidv4();

return [{
  json: {
    correlationId,
    startedAt,
    executionId,
    workflowName: 'WF-02-live-event-monitor',
    activeMatchesKey: 'wcic:active_matches',
  }
}];

// Verifica se há jogos ao vivo
// Redis SMEMBERS retorna { value: [id1, id2, ...] } ou { value: [] }
const result = $input.first().json;
const initData = $('Init').first().json;

const members = result.value || [];
const activeIds = Array.isArray(members) ? members.filter(Boolean) : [];

if (activeIds.length === 0) {
  return [{ json: { hasActiveMatches: false, activeIds: [], ...initData } }];
}

return [{ json: { hasActiveMatches: true, activeIds, activeCount: activeIds.length, ...initData } }];

