// Expande activeIds em itens individuais para o SplitInBatches
const { activeIds, correlationId, startedAt, executionId } = $input.first().json;

return activeIds.map(matchId => ({
  json: { matchId, correlationId, startedAt, executionId }
}));

// ============================================================
// Node: Prepare API Call
// Recupera o match UUID interno a partir do match_id Redis
// e prepara o cursor para filtrar eventos já processados
// ============================================================
const cursorResult = $input.first().json;
const batchItem = $('Split in Batches (5)').item.json;

let cursor = { lastExternalId: null, lastMinute: -1 };
if (cursorResult.value) {
  try { cursor = JSON.parse(cursorResult.value); } catch(e) { /* cursor corrompido, reinicia */ }
}

return [{
  json: {
    ...batchItem,
    cursor,
    // matchId aqui é o UUID interno do PostgreSQL (populado pelo WF-01 no SADD)
    apiUrl: `https://api.football-data.org/v4/matches/${batchItem.matchId}`,
  }
}];

// ============================================================
// Node: Handle API Error
// Incrementa contador de erros para este match_id
// Após 3 erros consecutivos, remove da active_matches
// ============================================================
const batchItem = $('Split in Batches (5)').item.json;
const errorCountKey = `wcic:errors:wf02:${batchItem.matchId}`;

console.error(`[WF-02] API error for match ${batchItem.matchId}: ${JSON.stringify($input.first().json)}`);

return [{
  json: {
    ...batchItem,
    error_count_key: errorCountKey,
    is_api_error: true,
  }
}];

// ============================================================
// Node: Parse Events
// Extrai eventos da resposta da API e filtra apenas os novos
// usando o cursor (lastExternalId ou lastMinute)
// ============================================================
const apiResponse = $input.first().json;
const prepData = $('Prepare API Call').item.json;
const { cursor } = prepData;

const body = apiResponse.body || apiResponse;

// Football-Data API retorna eventos em match.goals, match.bookings, match.substitutions
// Normaliza tudo em um array único de eventos
const rawGoals   = body.goals   || [];
const rawCards   = body.bookings || [];
const rawSubs    = body.substitutions || [];
const rawScore   = body.score || {};
const matchStatus = body.status || 'UNKNOWN';
const homeScore  = rawScore?.fullTime?.home;
const awayScore  = rawScore?.fullTime?.away;
const homeScoreHT = rawScore?.halfTime?.home;
const awayScoreHT = rawScore?.halfTime?.away;

const STATUS_MAP = {
  'IN_PLAY': 'live', 'PAUSED': 'halftime', 'FINISHED': 'finished',
  'SCHEDULED': 'scheduled', 'TIMED': 'scheduled',
};

// Normaliza goals
const normalizedEvents = [];

for (const g of rawGoals) {
  const extId = String(g.id || `goal_${g.minute?.regular || 0}_${g.scorer?.id || 'unk'}`);
  normalizedEvents.push({
    external_id: extId,
    event_type: g.type === 'OWN_GOAL' ? 'own_goal' : g.type === 'PENALTY' ? 'penalty_scored' : 'goal',
    minute: g.minute?.regular || 0,
    extra_minute: g.minute?.injury || null,
    period: 'regular',
    team_external_id: String(g.team?.id || ''),
    player_name: g.scorer?.name || null,
    player_external_id: String(g.scorer?.id || ''),
    assist_player_name: g.assist?.name || null,
    assist_player_external_id: String(g.assist?.id || ''),
    detail: null,
    raw: g,
  });
}

for (const c of rawCards) {
  const extId = String(c.id || `card_${c.minute?.regular || 0}_${c.player?.id || 'unk'}`);
  const cardType = c.card === 'RED_CARD' ? 'red_card' : c.card === 'YELLOW_RED_CARD' ? 'second_yellow' : 'yellow_card';
  normalizedEvents.push({
    external_id: extId,
    event_type: cardType,
    minute: c.minute?.regular || 0,
    extra_minute: c.minute?.injury || null,
    period: 'regular',
    team_external_id: String(c.team?.id || ''),
    player_name: c.player?.name || null,
    player_external_id: String(c.player?.id || ''),
    assist_player_name: null,
    assist_player_external_id: null,
    detail: null,
    raw: c,
  });
}

for (const s of rawSubs) {
  const extId = String(s.id || `sub_${s.minute?.regular || 0}_${s.playerOut?.id || 'unk'}`);
  normalizedEvents.push({
    external_id: extId,
    event_type: 'substitution',
    minute: s.minute?.regular || 0,
    extra_minute: s.minute?.injury || null,
    period: 'regular',
    team_external_id: String(s.team?.id || ''),
    player_name: s.playerIn?.name || null,
    player_external_id: String(s.playerIn?.id || ''),
    player_out_name: s.playerOut?.name || null,
    player_out_external_id: String(s.playerOut?.id || ''),
    detail: null,
    raw: s,
  });
}

// Filtra apenas eventos novos (external_id não visto antes)
// O cursor armazena o set de external_ids já processados
const processedIds = new Set(cursor.processedIds || []);
const newEvents = normalizedEvents.filter(e => !processedIds.has(e.external_id));

// Atualiza cursor com todos os IDs (novos + antigos)
const allProcessedIds = [...processedIds, ...newEvents.map(e => e.external_id)];
// Mantém apenas os últimos 200 IDs para não crescer indefinidamente
const updatedCursor = {
  processedIds: allProcessedIds.slice(-200),
  lastMinute: Math.max(...normalizedEvents.map(e => e.minute || 0), cursor.lastMinute || 0),
  updatedAt: new Date().toISOString(),
};

return [{
  json: {
    matchId: prepData.matchId,
    correlationId: prepData.correlationId,
    matchStatus: STATUS_MAP[matchStatus] || 'live',
    homeScore, awayScore, homeScoreHT, awayScoreHT,
    newEvents,
    newEventCount: newEvents.length,
    updatedCursor,
    hasNewEvents: newEvents.length > 0,
  }
}];

// Expande newEvents em itens individuais para processamento
const { newEvents, matchId, correlationId, homeScore, awayScore, homeScoreHT, awayScoreHT, matchStatus } = $input.first().json;

// Busca dados do match no banco para enriquecer notificações
// (times, placar etc.) - passado como contexto
return newEvents.map(evt => ({
  json: {
    ...evt,
    matchId,
    correlationId,
    homeScore,
    awayScore,
    homeScoreHT,
    awayScoreHT,
    matchStatus,
  }
}));

// ============================================================
// Node: Should Notify?
// Decide se este evento merece notificação para usuários
// Gols, cartões vermelhos e VAR confirmado → SIM
// Cartões amarelos, substituições → NÃO (apenas log)
// ============================================================
const evt = $('Expand Events').item.json;
const insertResult = $('Insert Event').item.json;

// Se ON CONFLICT DO NOTHING não inseriu nada, external_id era duplicata
// O node PostgreSQL retorna array vazio quando DO NOTHING ocorre
const wasInserted = insertResult?.id != null;

const NOTIFY_TYPES = {
  'goal': { notify: true, type: 'goal_alert', priority: 'critical' },
  'own_goal': { notify: true, type: 'own_goal_alert', priority: 'critical' },
  'penalty_scored': { notify: true, type: 'penalty_alert', priority: 'critical' },
  'red_card': { notify: true, type: 'red_card_alert', priority: 'high' },
  'second_yellow': { notify: true, type: 'second_yellow_alert', priority: 'high' },
  'var_overturned': { notify: true, type: 'var_alert', priority: 'high' },
  'yellow_card': { notify: false },
  'substitution': { notify: false },
  'var_review': { notify: false },
  'kick_off': { notify: false },
  'half_time': { notify: false },
  'full_time': { notify: false },
};

const config = NOTIFY_TYPES[evt.event_type] || { notify: false };

return [{
  json: {
    should_notify: config.notify && wasInserted,
    was_inserted: wasInserted,
    notification_type: config.type || null,
    notification_priority: config.priority || 'low',
    event: evt,
  }
}];

// ============================================================
// Node: Build Notification Payload
// Monta o payload padrão do WF-07
// ============================================================
const notifyData = $('Should Notify?').item.json;
const evt = notifyData.event;
const matchCtx = $input.first().json;

const homeScore = evt.homeScore ?? matchCtx.home_score ?? 0;
const awayScore = evt.awayScore ?? matchCtx.away_score ?? 0;

const payload = {
  type: notifyData.notification_type,
  priority: notifyData.notification_priority,
  channel: 'telegram',
  match_id: evt.matchId,
  event_type: evt.event_type,
  event_minute: evt.minute,
  correlation_id: evt.correlationId,
  content: {
    title: `${notifyData.notification_type.replace('_', ' ').toUpperCase()} - ${matchCtx.home_team || '?'} vs ${matchCtx.away_team || '?'}`,
    body: '',  // gerado pelo WF-07 Format Message node
    metadata: {
      caller_workflow: 'WF-02-live-event-monitor',
      home_team: matchCtx.home_team || '?',
      away_team: matchCtx.away_team || '?',
      home_code: matchCtx.home_code || '',
      away_code: matchCtx.away_code || '',
      home_score: homeScore,
      away_score: awayScore,
      minute: evt.minute,
      scorer: evt.player_name || null,
      assist: evt.assist_player_name || null,
      player: evt.player_name || null,
      team: matchCtx.home_team || '?',
      detail: evt.detail || null,
      venue: matchCtx.venue_name || null,
    }
  }
};

return [{ json: payload }];

